const executions = $input.first().json.data || [];
const last6h = new Date(Date.now() - 6 * 60 * 60 * 1000);

const recentErrors = executions.filter(e => new Date(e.startedAt) > last6h);

if (recentErrors.length === 0) {
  return [{ json: { hasErrors: false, count: 0 } }];
}

const summary = recentErrors.map(e => {
  return `- ${e.workflowData?.name || 'Unknown'}: ${e.stoppedAt ? 'Stopped' : 'Running'} (${new Date(e.startedAt).toLocaleString('tr-TR')})`;
}).join('\n');

return [{ json: { hasErrors: true, count: recentErrors.length, summary } }];
